#include <iostream>
#include <stdexcept>
#include <string>
#include <vector>

class Task {
    std::string name_;
public:
    explicit Task(std::string name) : name_(std::move(name)) {}
    void run() const {
        if (name_.empty())
            throw std::runtime_error("empty name");
        std::cout << "running: " << name_ << "\n";
    }
};

int main() {
    int n;
    std::cin >> n;
    std::vector<Task> tasks;
    for (int i = 0; i < n; ++i) {
        std::string s;
        std::cin >> s;
        tasks.emplace_back(s == "." ? "" : s);
    }
    for (const auto& t : tasks) {
        try {
            t.run();
        } catch (const std::runtime_error& e) {
            std::cout << "error: " << e.what() << "\n";
        }
    }
    return 0;
}

