#include <iostream>
#include <memory>

int main() {
    const int* ptr = nullptr;
    {
        auto p = std::make_unique<int>(42);
        ptr = p.get(); // ptr now points into p's storage
    } // p is destroyed here — ptr is dangling
    // BUG: reading through a dangling pointer
    std::cout << "value: " << *ptr << "\n";
    return 0;
}

solution_code:
#include <iostream>
#include <memory>

int main() {
    int value = 0;
    {
        auto p = std::make_unique<int>(42);
        value = *p; // copy the value before p is destroyed
    }
    std::cout << "value: " << value << "\n";
    return 0;
}
